import boto3
import os
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from urllib.parse import urlparse

app = Flask(__name__)

# AWS S3 Configuration
S3_BUCKET = 'your-s3-bucket-name'
s3_client = boto3.client('s3')

# Chrome WebDriver Configuration
chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--no-sandbox")
chrome_options.add_argument("--disable-dev-shm-usage")

def is_valid_url(url):
    parsed_url = urlparse(url)
    return parsed_url.scheme in ['http', 'https'] and parsed_url.netloc

def take_screenshot(url):
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    return screenshot

def upload_to_s3(file_content, file_name):
    s3_client.put_object(Bucket=S3_BUCKET, Key=file_name, Body=file_content, ContentType='image/png')
    return f"https://{S3_BUCKET}.s3.amazonaws.com/{file_name}"

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    url = request.json.get('url')
    if not url or not is_valid_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    try:
        screenshot = take_screenshot(url)
        file_name = f"screenshots/{os.path.basename(urlparse(url).path)}.png"
        s3_url = upload_to_s3(screenshot, file_name)
        return jsonify({'s3_url': s3_url})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)